   355→/*
   356→ * Applies the new map type
   357→ */
   358→int
   359→rewrite_map_apply(
   360→		struct rewrite_info *info,
   361→		struct rewrite_op *op,
   362→		struct rewrite_map *map,
   363→		struct berval *key,
   364→		struct berval *val
   365→)
   366→{
   367→	int rc = REWRITE_SUCCESS;
   368→
   369→	assert( info != NULL );
   370→	assert( op != NULL );
   371→	assert( map != NULL );
   372→	assert( key != NULL );
   373→	assert( val != NULL );
   374→
   375→	val->bv_val = NULL;
   376→	val->bv_len = 0;
   377→	
   378→	switch ( map->lm_type ) {
   379→	case REWRITE_MAP_SUBCONTEXT:
   380→		rc = rewrite_context_apply( info, op, 
   381→				( struct rewrite_context * )map->lm_data,
   382→				key->bv_val, &val->bv_val );
   383→		if ( val->bv_val != NULL ) {
   384→			if ( val->bv_val == key->bv_val ) {
   385→				val->bv_len = key->bv_len;
   386→				key->bv_val = NULL;
   387→			} else {
   388→				val->bv_len = strlen( val->bv_val );
   389→			}
   390→		}
   391→		break;
   392→
   393→	case REWRITE_MAP_SET_OP_VAR:
   394→	case REWRITE_MAP_SETW_OP_VAR:
   395→		rc = rewrite_var_set( &op->lo_vars, map->lm_name,
   396→				key->bv_val, 1 )
   397→			? REWRITE_SUCCESS : REWRITE_ERR;
   398→		if ( rc == REWRITE_SUCCESS ) {
   399→			if ( map->lm_type == REWRITE_MAP_SET_OP_VAR ) {
   400→				val->bv_val = strdup( "" );
   401→			} else {
   402→				val->bv_val = strdup( key->bv_val );
   403→				val->bv_len = key->bv_len;
   404→			}
   405→			if ( val->bv_val == NULL ) {
   406→				rc = REWRITE_ERR;
   407→			}
   408→		}
   409→		break;
   410→	
   411→	case REWRITE_MAP_GET_OP_VAR: {
   412→		struct rewrite_var *var;
   413→
   414→		var = rewrite_var_find( op->lo_vars, map->lm_name );
   415→		if ( var == NULL ) {
   416→			rc = REWRITE_ERR;
   417→		} else {
   418→			val->bv_val = strdup( var->lv_value.bv_val );
   419→			val->bv_len = var->lv_value.bv_len;
   420→			if ( val->bv_val == NULL ) {
   421→				rc = REWRITE_ERR;
   422→			}
   423→		}
   424→		break;	
   425→	}
   426→
   427→	case REWRITE_MAP_SET_SESN_VAR:
   428→	case REWRITE_MAP_SETW_SESN_VAR:
   429→		if ( op->lo_cookie == NULL ) {
   430→			rc = REWRITE_ERR;
   431→			break;
   432→		}
   433→		rc = rewrite_session_var_set( info, op->lo_cookie, 
   434→				map->lm_name, key->bv_val );
   435→		if ( rc == REWRITE_SUCCESS ) {
   436→			if ( map->lm_type == REWRITE_MAP_SET_SESN_VAR ) {
   437→				val->bv_val = strdup( "" );
   438→			} else {
   439→				val->bv_val = strdup( key->bv_val );
   440→				val->bv_len = key->bv_len;
   441→			}
   442→			if ( val->bv_val == NULL ) {
   443→				rc = REWRITE_ERR;
   444→			}
   445→		}
   446→		break;
   447→
   448→	case REWRITE_MAP_GET_SESN_VAR:
   449→		rc = rewrite_session_var_get( info, op->lo_cookie,
   450→				map->lm_name, val );
   451→		break;		
   452→
   453→	case REWRITE_MAP_GET_PARAM:
   454→		rc = rewrite_param_get( info, map->lm_name, val );
   455→		break;
   456→
   457→	case REWRITE_MAP_BUILTIN: {
   458→		struct rewrite_builtin_map *bmap = map->lm_data;
   459→
   460→		if ( bmap->lb_mapper && bmap->lb_mapper->rm_apply )
   461→			rc = bmap->lb_mapper->rm_apply( bmap->lb_private, key->bv_val,
   462→				val );
   463→		else
   464→			rc = REWRITE_ERR;
   465→		break;
   466→	}
   467→
   468→	default:
   469→		rc = REWRITE_ERR;
   470→		break;
   471→	}
   472→
   473→	return rc;
   474→}
   475→
   476→void
   477→rewrite_builtin_map_free(
   478→		void *tmp
   479→)
   480→{
   481→	struct rewrite_builtin_map *map = ( struct rewrite_builtin_map * )tmp;
   482→
   483→	assert( map != NULL );
   484→
   485→	if ( map->lb_mapper && map->lb_mapper->rm_destroy )
   486→		map->lb_mapper->rm_destroy( map->lb_private );
   487→
   488→	free( map->lb_name );
   489→	free( map );
   490→}
   491→
   492→int
   493→rewrite_map_destroy(
   494→		struct rewrite_map **pmap
   495→)
   496→{
   497→	struct rewrite_map *map;
   498→	
   499→	assert( pmap != NULL );
   500→	assert( *pmap != NULL );
   501→
   502→	map = *pmap;
   503→
   504→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   505→	ldap_pvt_thread_mutex_lock( &map->lm_mutex );
   506→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   507→
   508→	if ( map->lm_name ) {
   509→		free( map->lm_name );
   510→		map->lm_name = NULL;
   511→	}
   512→
   513→	if ( map->lm_subst ) {
   514→		rewrite_subst_destroy( &map->lm_subst );
   515→	}
   516→
   517→#ifdef USE_REWRITE_LDAP_PVT_THREADS
   518→	ldap_pvt_thread_mutex_unlock( &map->lm_mutex );
   519→	ldap_pvt_thread_mutex_destroy( &map->lm_mutex );
   520→#endif /* USE_REWRITE_LDAP_PVT_THREADS */
   521→
   522→	free( map );
   523→	*pmap = NULL;
   524→	
   525→	return 0;
   526→}
   527→
   528→/* ldapmap.c */
   529→extern const rewrite_mapper rewrite_ldap_mapper;
   530→
   531→/* escapemap.c */
   532→extern const rewrite_mapper rewrite_escape_mapper;
   533→
   534→const rewrite_mapper *
   535→rewrite_mapper_find(
   536→	const char *name
   537→)
   538→{
   539→	int i;
   540→
   541→	if ( !strcasecmp( name, "ldap" ))
   542→		return &rewrite_ldap_mapper;
   543→
   544→	if ( !strcasecmp( name, "escape" ))
   545→		return &rewrite_escape_mapper;
   546→
   547→	for (i=0; i<num_mappers; i++)
   548→		if ( !strcasecmp( name, mappers[i]->rm_name ))
   549→			return mappers[i];
   550→	return NULL;
   551→}
   552→
   553→int
   554→rewrite_mapper_register(
   555→	const rewrite_mapper *map
   556→)
   557→{
   558→	if ( num_mappers % MAPPER_ALLOC == 0 ) {
   559→		const rewrite_mapper **mnew;
